class Solution {
    public int minSwaps(int[] nums) {
        int n = nums.length;
        int ones = 0;
        for (int num : nums) {
            if (num == 1) ones++;
        }
        if (ones == 0) return 0;
        int minSwaps = Integer.MAX_VALUE;
        for (int i = 0; i < n; i++) {
            int swaps = 0;
            int j = i;
            while (nums[j] != 1) {
                j = (j + 1) % n;
                swaps++;
            }
            int k = j;
            while (k != i) {
                if (nums[k] == 1) {
                    swaps++;
                    k = (k + 1) % n;
                } else {
                    k = (k - 1 + n) % n;
                }
            }
            minSwaps = Math.min(minSwaps, swaps);
        }
        return minSwaps;
    }
}
